from jsonb_array_elements('[{"id":"w-springmesser","kategorie":"waffe","name":"Spring-/Fallmesser (verbotene Bauart)","synonyme":["Switchblade","automatik messer","OTF"],"wirkstoff":"","praegung":"","farbe":"metallic","form":"klappmesser","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2, Abschnitt 1 (verbotene Gegenstände)","begruendung":"Springmesser bestimmter Bauart und Fallmesser zählen zu den verbotenen Gegenständen. Umgang/Besitz ist grundsätzlich strafbar.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Italian%20switchblade.jpg","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-butterfly","kategorie":"waffe","name":"Butterflymesser (Balisong)","synonyme":["balisong","schmetterlingsmesser"],"wirkstoff":"","praegung":"","farbe":"metallic","form":"klappmesser","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2, Abschnitt 1 (verbotene Gegenstände)","begruendung":"Butterflymesser gehören zu den verbotenen Gegenständen nach dem Waffengesetz. Besitz und Führen sind grundsätzlich strafbar.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Balisong-knife.jpg","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-schreckschuss","kategorie":"waffe","name":"Schreckschuss-/Gaspistole (führen ohne Kleinen Waffenschein)","synonyme":["srs","gaswaffe","platzpatrone","ppk gas"],"wirkstoff":"","praegung":"","farbe":"schwarz","form":"pistole","ampel":"gelb","einstufung":"Ordnungswidrigkeit","gesetz":"WaffG §§ 10, 53 (Führen ohne Kleinen Waffenschein)","begruendung":"Der Besitz zuhause ist ab 18 erlaubt. Das Führen in der Öffentlichkeit ohne „Kleinen Waffenschein“ ist eine Ordnungswidrigkeit (Bußgeld). Ohne PTB-Zulassung kann es jedoch strafbar sein.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Walther%20P99%20pistol.jpg","quellen":["waffg","bayern"]},{"id":"w-einhandmesser","kategorie":"waffe","name":"Einhandmesser / feststehendes Messer >12 cm (führen)","synonyme":["einhand","klappmesser","feststehend","tactical"],"wirkstoff":"","praegung":"","farbe":"metallic","form":"messer","ampel":"gelb","einstufung":"Ordnungswidrigkeit","gesetz":"WaffG § 42a (Führungsverbot), § 53 (Bußgeld)","begruendung":"Besitz erlaubt. Das Führen von Einhandmessern oder feststehenden Messern mit Klinge über 12 cm in der Öffentlichkeit ist verboten (Ordnungswidrigkeit). Strengere Regeln in Waffenverbotszonen.","bild":"https://upload.wikimedia.org/wikipedia/commons/4/47/Pocket_knife.jpg","quellen":["waffg","bayern"]},{"id":"w-schusswaffe","kategorie":"waffe","name":"Scharfe Schusswaffe ohne Erlaubnis","synonyme":["pistole","revolver","gewehr","feuerwaffe"],"wirkstoff":"","praegung":"","farbe":"schwarz","form":"pistole","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG §§ 2, 52 (Erwerb/Besitz ohne Erlaubnis)","begruendung":"Erwerb, Besitz oder Führen scharfer Schusswaffen ohne die erforderliche Erlaubnis (z. B. Waffenbesitzkarte) ist eine Straftat.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Glock%2017%20gen4.jpg","quellen":["waffg","bayern"]},{"id":"w-pfefferspray","kategorie":"waffe","name":"Pfefferspray (Tierabwehr)","synonyme":["ko spray","reizgas","tierabwehrspray","OC"],"wirkstoff":"","praegung":"","farbe":"dose","form":"spraydose","ampel":"gruen","einstufung":"Legal/erlaubt","gesetz":"WaffG (kein erlaubnispflichtiger Gegenstand bei Tierabwehr-Kennzeichnung)","begruendung":"Pfefferspray mit Kennzeichnung „zur Tierabwehr“ darf von Erwachsenen frei gekauft und mitgeführt werden. Reizstoffsprühgeräte mit Prüfzeichen sind ebenfalls erlaubt.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Pepper%20spray.jpg","quellen":["waffg","bayern"]},{"id":"d-heroin","kategorie":"btm","name":"Heroin","synonyme":["diamorphin","diacetylmorphin","h","smack"],"wirkstoff":"Diamorphin","praegung":"","farbe":"braun/weiß","form":"pulver","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage I (nicht verkehrsfähig), § 29","strafmass":"Besitz/Erwerb: Freiheitsstrafe bis zu 5 Jahren oder Geldstrafe (§ 29 BtMG). Handel/Einfuhr nicht geringer Mengen: Freiheitsstrafe nicht unter 1 Jahr (§ 29a/30/30a BtMG). Im Einzelfall kann bei geringen Mengen zum Eigenkonsum von Strafe abgesehen werden.","begruendung":"Heroin ist ein nicht verkehrsfähiges Betäubungsmittel. Besitz, Erwerb und Handel sind strafbar.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Bayer%20Heroin%20bottle.jpg","quellen":["btmg","bfarm"]},{"id":"d-kokain","kategorie":"btm","name":"Kokain","synonyme":["coke","koks","crack","benzoylmethylecgonin"],"wirkstoff":"Cocain","praegung":"","farbe":"weiß","form":"pulver/kristall","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage II/III-Bezug, Straßenhandel nach § 29","begruendung":"Kokain unterliegt dem BtMG. Besitz und Erwerb zum Konsum ohne Erlaubnis sind strafbar.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Cocaine.jpg","quellen":["btmg","bfarm"]},{"id":"d-mdma","kategorie":"btm","name":"MDMA / Ecstasy","synonyme":["xtc","ecstasy","molly","e","pille","emma"],"wirkstoff":"MDMA","praegung":"logo/symbol","farbe":"bunt","form":"tablette/kristall","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage I, § 29","begruendung":"MDMA ist ein nicht verkehrsfähiges Betäubungsmittel. Besitz und Erwerb sind strafbar. Ecstasy-Tabletten tragen oft Logos/Prägungen.","bild":"","quellen":["btmg","bfarm"]},{"id":"d-amphetamin","kategorie":"btm","name":"Amphetamin (Speed)","synonyme":["speed","pep","amph","paste"],"wirkstoff":"Amphetamin","praegung":"","farbe":"weiß/beige","form":"pulver/paste","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage II/III, illegaler Besitz nach § 29","begruendung":"Amphetamin unterliegt dem BtMG. Besitz ohne Erlaubnis/Verschreibung ist strafbar.","bild":"","quellen":["btmg","bfarm"]},{"id":"d-cannabis","kategorie":"btm","name":"Cannabis (Marihuana/Haschisch)","synonyme":["weed","gras","marihuana","haschisch","thc","dope"],"wirkstoff":"THC","praegung":"","farbe":"grün/braun","form":"blüte/harz","ampel":"gelb","einstufung":"Teilweise erlaubt – Grenzen beachten","gesetz":"Konsumcannabisgesetz (KCanG) seit 2024; bei Überschreitung straf-/bußgeldbewehrt","begruendung":"Seit 2024 ist Cannabis für Erwachsene in engen Grenzen erlaubt (begrenzte Besitzmenge, Eigenanbau, Konsumregeln). Bei Überschreitung der Mengen, Abgabe an Minderjährige oder Konsum an verbotenen Orten drohen Bußgeld oder Strafe. Die genaue Lage ist komplex – Quellen prüfen.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Macro%20cannabis%20bud.jpg","quellen":["kcang","btmg"]},{"id":"d-lsd","kategorie":"btm","name":"LSD","synonyme":["acid","pappe","trip","lyserg"],"wirkstoff":"Lysergsäurediethylamid","praegung":"motiv","farbe":"papier","form":"blotter/pappe","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage I, § 29","begruendung":"LSD ist ein nicht verkehrsfähiges Betäubungsmittel. Besitz und Erwerb sind strafbar.","bild":"","quellen":["btmg","bfarm"]},{"id":"a-diazepam","kategorie":"arznei","name":"Diazepam (z. B. Valium)","synonyme":["valium","benzo","benzodiazepin","dia"],"wirkstoff":"Diazepam","praegung":"z. B. „10“ / Hersteller-Code","farbe":"weiß/gelb/blau","form":"rund, oft mit Bruchrille","merkmale":"Kleine runde Tablette mit Bruchrille (teilbar). Farbe variiert nach Dosis: 2 mg oft weiß, 5 mg gelb, 10 mg blau. Häufig Dosiszahl oder Herstellerkürzel eingeprägt. Durchmesser ca. 5–8 mm.","ampel":"gelb","einstufung":"Verschreibungspflichtig – Besitz ohne Rezept problematisch","gesetz":"AMG (Verschreibungspflicht); höhere Mengen ggf. BtMG-relevant","begruendung":"Benzodiazepin, verschreibungspflichtig. Mit ärztlichem Rezept legal. Besitz ohne Rezept bzw. größere Mengen können straf-/ordnungsrechtlich relevant sein. Über die Prägung in Gelbe Liste Identa identifizierbar.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Diazepam%20tablets.jpg","quellen":["amg","identa"]},{"id":"a-lorazepam","kategorie":"arznei","name":"Lorazepam (z. B. Tavor)","synonyme":["tavor","benzo","expidet"],"wirkstoff":"Lorazepam","praegung":"„1,0“ / „2,5“","farbe":"weiß","form":"rund/oval","merkmale":"Sehr kleine weiße Tablette, oft mit Dosisangabe („1,0“ oder „2,5“) und Bruchkerbe. Tavor expidet: weißes Schmelzplättchen. Durchmesser ca. 5–6 mm.","ampel":"gelb","einstufung":"Verschreibungspflichtig – Besitz ohne Rezept problematisch","gesetz":"AMG (Verschreibungspflicht)","begruendung":"Benzodiazepin, verschreibungspflichtig. Mit Rezept legal; ohne Rezept rechtlich problematisch. Prägung über Gelbe Liste Identa abgleichbar.","bild":"","quellen":["amg","identa"]},{"id":"a-oxycodon","kategorie":"arznei","name":"Oxycodon (Opioid-Schmerzmittel)","synonyme":["oxy","oxygesic","oxycontin","opioid"],"wirkstoff":"Oxycodon","praegung":"Dosis-Zahl","farbe":"div.","form":"rund/oval","merkmale":"Filmtablette, Farbe je nach Dosis verschieden (z. B. 5/10/20/40/80 mg). Oft mit Dosiszahl und Herstellerkürzel (z. B. „OC“, „OP“) geprägt. Retardtabletten sind meist rund und glänzend überzogen.","ampel":"rot","einstufung":"BtM-pflichtig – ohne BtM-Rezept Straftat","gesetz":"BtMG Anlage III (verschreibungsfähig); ohne BtM-Rezept § 29","begruendung":"Starkes Opioid, fällt unter das BtMG (Anlage III). Nur mit speziellem BtM-Rezept legal. Besitz ohne gültige Verschreibung ist strafbar.","bild":"","quellen":["btmg","amg"]},{"id":"a-tramadol","kategorie":"arznei","name":"Tramadol","synonyme":["tramal","tilidin?","opioid schwach"],"wirkstoff":"Tramadol","praegung":"„T“ / Dosis","farbe":"weiß/gelb","form":"kapsel/tablette","merkmale":"Häufig als Kapsel (grün/gelb) oder weiße Retardtablette. Geprägt oft „T“ + Dosis (50/100/150/200). Tropfen sind klare Flüssigkeit. Durchmesser/Länge je nach Form.","ampel":"gelb","einstufung":"Verschreibungspflichtig (kein BtM) – ohne Rezept problematisch","gesetz":"AMG (Verschreibungspflicht, nicht BtMG)","begruendung":"Schwaches Opioid, verschreibungspflichtig, aber (anders als Tilidin/Tramadol-Kombis in bestimmten Formen) i. d. R. nicht BtM-pflichtig. Mit Rezept legal.","bild":"","quellen":["amg","identa"]},{"id":"a-ibuprofen","kategorie":"arznei","name":"Ibuprofen (400/600/800)","synonyme":["ibu","nurofen","dolormin","schmerztablette"],"wirkstoff":"Ibuprofen","praegung":"„IBU 400“, „600“","farbe":"weiß","form":"länglich/rund","merkmale":"Meist weiße, ovale/längliche Filmtablette (400 mg) oder rund. Oft Prägung „IBU 400/600/800“ oder Herstellerkürzel. 800 mg sind größer und verschreibungspflichtig. Dragees teils glänzend überzogen.","ampel":"gruen","einstufung":"Legal (rezeptfrei bis 400 mg)","gesetz":"AMG (apothekenpflichtig; 400 mg rezeptfrei, 600/800 mg verschreibungspflichtig)","begruendung":"Gängiges Schmerzmittel. Bis 400 mg rezeptfrei in der Apotheke erhältlich; höhere Dosierungen sind verschreibungspflichtig, aber legal mit Rezept.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Ibuprofen%20tablets.jpg","quellen":["amg","identa"]},{"id":"a-ass","kategorie":"arznei","name":"ASS / Aspirin","synonyme":["aspirin","acetylsalicylsäure","ass 100","ass 500"],"wirkstoff":"Acetylsalicylsäure","praegung":"„ASS 500“, Bayer-Kreuz","farbe":"weiß","form":"rund","merkmale":"Weiße runde Tablette mit Bruchrille; Aspirin oft mit eingeprägtem „Bayer-Kreuz“. ASS 100 (Blutverdünnung) ist kleiner als ASS 500. Geruchlos bis leicht essigartig.","ampel":"gruen","einstufung":"Legal (frei verkäuflich)","gesetz":"AMG (frei verkäuflich / apothekenpflichtig je nach Packung)","begruendung":"Klassisches Schmerz-/Fiebermittel, frei bzw. apothekenpflichtig erhältlich. Legal.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Aspirin-B-700.jpg","quellen":["amg","identa"]},{"id":"w-kriegswaffe","kategorie":"waffe","name":"Kriegswaffe (Maschinengewehr, Granate o. Ä.)","synonyme":["kriegswaffe","mg","granate","panzerfaust","vollautomatik kriegsgerät"],"wirkstoff":"","praegung":"","farbe":"","form":"kriegsgerät","ampel":"rot","einstufung":"Straftat","gesetz":"Kriegswaffenkontrollgesetz (KrWaffKG); WaffG Anlage 2 Abschnitt 1","begruendung":"Kriegswaffen fallen unter das Kriegswaffenkontrollgesetz. Umgang ohne Genehmigung ist eine schwere Straftat.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-vollautomat","kategorie":"waffe","name":"Vollautomatische Schusswaffe","synonyme":["maschinenpistole","sturmgewehr","vollautomat","automatikwaffe"],"wirkstoff":"","praegung":"","farbe":"schwarz","form":"schusswaffe","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1 (verbotene Waffen)","begruendung":"Vollautomatische Schusswaffen gehören zu den verbotenen Waffen. Erwerb und Besitz sind grundsätzlich strafbar.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-anscheinswaffe","kategorie":"waffe","name":"Anscheinswaffe (täuschend echte Nachbildung)","synonyme":["softair anscheinswaffe","deko echtwaffe","replika"],"wirkstoff":"","praegung":"","farbe":"","form":"schusswaffen-nachbildung","ampel":"gelb","einstufung":"Ordnungswidrigkeit","gesetz":"WaffG Anlage 2 Abschnitt 1 Nr. 1.6 (Führungsverbot Anscheinswaffen)","begruendung":"Das Führen von Anscheinswaffen (sehen aus wie echte Waffen) in der Öffentlichkeit ist verboten und als Ordnungswidrigkeit bußgeldbewehrt.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-wurfstern","kategorie":"waffe","name":"Wurfstern / Wurfmesser (verbotene Bauart)","synonyme":["shuriken","wurfstern","ninja stern","wurfmesser"],"wirkstoff":"","praegung":"","farbe":"metallic","form":"wurfwaffe","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1 (verbotene Gegenstände)","begruendung":"Wurfsterne zählen zu den verbotenen Gegenständen. Umgang und Besitz sind grundsätzlich strafbar.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-schlagring","kategorie":"waffe","name":"Schlagring","synonyme":["knuckle","faustschützer","brass knuckles"],"wirkstoff":"","praegung":"","farbe":"metallic","form":"hiebwaffe","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1 (verbotene Gegenstände)","begruendung":"Schlagringe gehören zu den verbotenen Gegenständen. Besitz und Führen sind grundsätzlich strafbar.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-stahlrute","kategorie":"waffe","name":"Stahlrute / Totschläger / Teleskopschlagstock (bestimmte Bauart)","synonyme":["stahlrute","totschläger","schlagstock","teleskopschlagstock"],"wirkstoff":"","praegung":"","farbe":"metallic","form":"hiebwaffe","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1 (verbotene Gegenstände)","begruendung":"Stahlruten, Totschläger und Schlagstöcke bestimmter Bauart sind verbotene Gegenstände. Umgang ist grundsätzlich strafbar.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-wurfsterne-praezi","kategorie":"waffe","name":"Präzisionsschleuder","synonyme":["präzisionsschleuder","sportschleuder mit armstütze","zwille"],"wirkstoff":"","praegung":"","farbe":"","form":"schleuder","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1 (verbotene Gegenstände)","begruendung":"Präzisionsschleudern (mit Armstütze) zählen zu den verbotenen Gegenständen. Besitz ist grundsätzlich strafbar.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-elektroimpuls","kategorie":"waffe","name":"Elektroimpulsgerät / Taser (ohne PTB-Zulassung)","synonyme":["taser","elektroschocker","distanz-elektroimpulsgerät"],"wirkstoff":"","praegung":"","farbe":"schwarz","form":"elektrogerät","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1 (verboten ohne amtliches Prüfzeichen)","begruendung":"Elektroimpulsgeräte sind verboten, sofern sie nicht amtlich als gesundheitlich unbedenklich zugelassen sind (Prüfzeichen). Distanz-Elektroimpulsgeräte (Taser) sind grundsätzlich verboten.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-faustmesser","kategorie":"waffe","name":"Faustmesser / Stahlrutenmesser / Faltmesser mit Arretierung (verbotene Bauart)","synonyme":["faustmesser","push dagger","stilett","springstilett"],"wirkstoff":"","praegung":"","farbe":"metallic","form":"messer","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1 (verbotene Gegenstände)","begruendung":"Faustmesser und bestimmte Stich-/Stoßwaffen sind verbotene Gegenstände. Umgang ist grundsätzlich strafbar.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-molotow","kategorie":"waffe","name":"Molotowcocktail / unkonventioneller Spreng-/Brandsatz","synonyme":["molotow","brandsatz","sprengsatz"],"wirkstoff":"","praegung":"","farbe":"","form":"brandsatz","ampel":"rot","einstufung":"Straftat","gesetz":"WaffG Anlage 2 Abschnitt 1; Sprengstoffgesetz","begruendung":"Unkonventionelle Spreng- und Brandvorrichtungen sind verboten. Herstellung und Besitz sind schwere Straftaten.","bild":"","quellen":["waffg_anl","waffg","bayern"]},{"id":"w-luftgewehr","kategorie":"waffe","name":"Luftgewehr / Luftpistole (≤ 7,5 Joule, F-Zeichen)","synonyme":["luftgewehr","luftpistole","airgun","co2 waffe","7,5 joule"],"wirkstoff":"","praegung":"","farbe":"","form":"druckluftwaffe","ampel":"gruen","einstufung":"Legal/erlaubt (ab 18)","gesetz":"WaffG (frei ab 18 bei ≤ 7,5 J und F-im-Fünfeck-Zeichen)","begruendung":"Luftdruckwaffen mit höchstens 7,5 Joule und F-Zeichen dürfen ab 18 frei erworben werden. Führen in der Öffentlichkeit nur eingeschränkt (nicht schussbereit).","bild":"","quellen":["waffg","bayern"]},{"id":"w-softair","kategorie":"waffe","name":"Softair (≤ 0,5 Joule)","synonyme":["softair","airsoft","soft air"],"wirkstoff":"","praegung":"","farbe":"","form":"druckluftwaffe","ampel":"gruen","einstufung":"Legal/erlaubt (ab 14)","gesetz":"WaffG (Spielzeug-/Anscheinswaffen-Regeln beachten)","begruendung":"Softairwaffen bis 0,5 Joule sind ab 14 erlaubt. Achtung: Führen in der Öffentlichkeit kann als Anscheinswaffe verboten sein.","bild":"","quellen":["waffg","bayern"]},{"id":"w-taschenmesser","kategorie":"waffe","name":"Taschenmesser / Klinge ≤ 12 cm (kein Einhandmesser)","synonyme":["taschenmesser","sackmesser","schweizer messer"],"wirkstoff":"","praegung":"","farbe":"","form":"messer","ampel":"gruen","einstufung":"Legal/erlaubt","gesetz":"WaffG § 42a (nicht erfasst, wenn keine Einhand-/Feststehbauart > 12 cm)","begruendung":"Normale Taschenmesser (zweihändig zu öffnen, Klinge bis 12 cm) dürfen geführt werden. In Waffenverbotszonen können strengere Regeln gelten.","bild":"","quellen":["waffg","bayern"]},{"id":"d-methamphetamin","kategorie":"btm","name":"Methamphetamin (Crystal Meth)","synonyme":["crystal","meth","crystal meth","ice","pervitin"],"wirkstoff":"Metamfetamin","praegung":"","farbe":"weiß/kristall","form":"kristall/pulver","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage II/III-Bezug; illegaler Besitz § 29","begruendung":"Methamphetamin unterliegt dem BtMG. Besitz und Erwerb ohne Erlaubnis sind strafbar.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Crystal%20Meth.jpg","quellen":["btmg","bfarm"]},{"id":"d-psilocybin","kategorie":"btm","name":"Psilocybin / Psilocin (Zauberpilze)","synonyme":["magic mushrooms","zauberpilze","pilze","shrooms","psilo"],"wirkstoff":"Psilocybin","praegung":"","farbe":"","form":"pilz","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage I, § 29","begruendung":"Psilocybin/Psilocin (Wirkstoffe der „Magic Mushrooms“) sind nicht verkehrsfähig. Besitz und Erwerb sind strafbar.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Psilocybe%20semilanceata%206514.jpg","quellen":["btmg","bfarm"]},{"id":"d-ghb","kategorie":"btm","name":"GHB / GBL (Liquid Ecstasy, K.-o.-Tropfen)","synonyme":["ghb","gbl","liquid ecstasy","ko tropfen","g"],"wirkstoff":"Gamma-Hydroxybuttersäure","praegung":"","farbe":"farblos","form":"flüssigkeit","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage II (GHB); GBL als Grundstoff überwacht","begruendung":"GHB unterliegt dem BtMG; Besitz ohne Erlaubnis ist strafbar. GBL (Vorläufer) wird als Grundstoff überwacht.","bild":"","quellen":["btmg","bfarm"]},{"id":"d-ketamin","kategorie":"btm","name":"Ketamin","synonyme":["keta","special k","k","ketanest"],"wirkstoff":"Ketamin","praegung":"","farbe":"weiß","form":"pulver/lösung","ampel":"gelb","einstufung":"Verschreibungspflichtig – illegaler Besitz strafbar","gesetz":"AMG (verschreibungspflichtiges Anästhetikum); illegaler Handel strafbar","begruendung":"Ketamin ist ein verschreibungspflichtiges Narkosemittel (in D nicht im BtMG, aber AMG). Medizinisch legal; missbräuchlicher Besitz/Handel ist strafbar.","bild":"","quellen":["amg","bfarm"]},{"id":"d-fentanyl","kategorie":"btm","name":"Fentanyl","synonyme":["fenta","fentanyl pflaster","durogesic"],"wirkstoff":"Fentanyl","praegung":"","farbe":"","form":"pflaster/lösung","ampel":"rot","einstufung":"BtM-pflichtig – ohne BtM-Rezept Straftat","gesetz":"BtMG Anlage III (verschreibungsfähig); ohne BtM-Rezept § 29","begruendung":"Hochpotentes Opioid. Nur mit BtM-Rezept legal. Besitz ohne gültige Verschreibung ist strafbar; bereits kleine Mengen sind sehr gefährlich.","bild":"","quellen":["btmg","bfarm"]},{"id":"d-morphin","kategorie":"btm","name":"Morphin","synonyme":["morphium","ms contin","morphin"],"wirkstoff":"Morphin","praegung":"Dosis","farbe":"","form":"tablette/lösung","ampel":"rot","einstufung":"BtM-pflichtig – ohne BtM-Rezept Straftat","gesetz":"BtMG Anlage III (verschreibungsfähig)","begruendung":"Starkes Opioid-Schmerzmittel. Nur mit BtM-Rezept legal; Besitz ohne gültige Verschreibung ist strafbar.","bild":"","quellen":["btmg","bfarm"]},{"id":"d-methadon","kategorie":"btm","name":"Methadon / Polamidon (Substitution)","synonyme":["methadon","polamidon","l-polamidon","substitol"],"wirkstoff":"Methadon","praegung":"","farbe":"","form":"lösung/tablette","ampel":"rot","einstufung":"BtM-pflichtig – ohne BtM-Rezept Straftat","gesetz":"BtMG Anlage III (Substitutionsmittel)","begruendung":"Synthetisches Opioid für die Substitutionstherapie. Nur ärztlich verordnet legal; Weitergabe/Besitz ohne Verschreibung strafbar.","bild":"","quellen":["btmg","bfarm"]},{"id":"d-tilidin","kategorie":"btm","name":"Tilidin (hochdosiert/ohne Naloxon)","synonyme":["tilidin","valoron","tili"],"wirkstoff":"Tilidin","praegung":"Dosis","farbe":"","form":"tropfen/tablette","ampel":"rot","einstufung":"Teilweise BtM-pflichtig – ohne Rezept Straftat","gesetz":"BtMG Anlage III (unretardierte Form/Tropfen); AMG sonst","begruendung":"Opioid. In bestimmten Formen (z. B. unretardierte Tropfen) BtM-pflichtig. Missbräuchlicher Besitz ohne Verschreibung ist strafbar.","bild":"","quellen":["btmg","amg"]},{"id":"d-codein","kategorie":"btm","name":"Codein / Dihydrocodein (höhere Dosen)","synonyme":["codein","dhc","codeinsaft","hustensaft codein"],"wirkstoff":"Codein","praegung":"","farbe":"","form":"saft/tablette","ampel":"gelb","einstufung":"Verschreibungspflichtig – höhere Dosen BtM-pflichtig","gesetz":"AMG (verschreibungspflichtig); höhere Dosen BtMG Anlage III","begruendung":"Opioides Hustenmittel/Schmerzmittel. Verschreibungspflichtig; ab bestimmten Mengen/Konzentrationen BtM-pflichtig. Missbrauch ist strafbar.","bild":"","quellen":["btmg","amg"]},{"id":"d-cannabis-medizin","kategorie":"btm","name":"Medizinalcannabis (auf Rezept)","synonyme":["medizinisches cannabis","cannabisblüten rezept","dronabinol"],"wirkstoff":"THC/CBD","praegung":"","farbe":"grün","form":"blüte/extrakt","ampel":"gelb","einstufung":"Nur mit Rezept legal","gesetz":"BtMG / Medizinal-Cannabisgesetz (MedCanG)","begruendung":"Cannabis zu medizinischen Zwecken ist nur mit ärztlicher Verordnung legal. Ohne Rezept gelten die allgemeinen Regeln (KCanG/BtMG).","bild":"","quellen":["btmg","kcang","bfarm"]},{"id":"d-2cb","kategorie":"btm","name":"2C-B / NPS („Legal Highs“/Research Chemicals)","synonyme":["2cb","research chemical","legal high","nps","badesalz"],"wirkstoff":"diverse","praegung":"","farbe":"","form":"pulver/tablette","ampel":"rot","einstufung":"Straftat","gesetz":"BtMG Anlage I bzw. Neue-psychoaktive-Stoffe-Gesetz (NpSG)","begruendung":"Viele „Research Chemicals“/„Legal Highs“ sind durch BtMG oder das NpSG erfasst. Besitz und Handel sind in der Regel strafbar – „legal“ ist irreführend.","bild":"","quellen":["btmg","bfarm"]},{"id":"d-amphetamin-rezept","kategorie":"btm","name":"Methylphenidat (Ritalin) / ADHS-Stimulanzien","synonyme":["ritalin","methylphenidat","medikinet","concerta","elvanse","lisdexamfetamin"],"wirkstoff":"Methylphenidat","praegung":"„CG“ / Dosis","farbe":"weiß/bunt","form":"tablette/kapsel","merkmale":"Ritalin: kleine runde Tablette, oft mit Herstellerkürzel geprägt. Retard-Formen (Concerta) als zylindrische Tablette, Medikinet/Elvanse als zweifarbige Kapsel. Farbe je nach Dosis.","ampel":"rot","einstufung":"BtM-pflichtig – ohne BtM-Rezept Straftat","gesetz":"BtMG Anlage III","begruendung":"ADHS-Stimulanzien wie Methylphenidat sind BtM-pflichtig. Nur mit BtM-Rezept legal; Besitz/Weitergabe ohne Verschreibung ist strafbar.","bild":"","quellen":["btmg","amg","identa"]},{"id":"a-paracetamol","kategorie":"arznei","name":"Paracetamol","synonyme":["paracetamol","ben-u-ron","para","acetaminophen"],"wirkstoff":"Paracetamol","praegung":"„500“","farbe":"weiß","form":"länglich/rund","merkmale":"Weiße, längliche oder runde Tablette, häufig mit Bruchkerbe und Prägung „500“. Größere 500-mg-Tabletten sind länglich; Brausetabletten flach und rund. Geruchlos.","ampel":"gruen","einstufung":"Legal (rezeptfrei)","gesetz":"AMG (apothekenpflichtig, kleine Packungen frei)","begruendung":"Gängiges Schmerz-/Fiebermittel, rezeptfrei erhältlich. Achtung: Überdosis ist lebergiftig.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Paracetamol%20tablets.jpg","quellen":["amg","identa"]},{"id":"a-novalgin","kategorie":"arznei","name":"Metamizol (Novalgin)","synonyme":["novalgin","metamizol","novaminsulfon"],"wirkstoff":"Metamizol","praegung":"„500“/Code","farbe":"weiß","form":"tablette/tropfen","merkmale":"Große weiße runde Tablette (500 mg) mit Bruchkerbe, oder klare Tropfen. Häufig nur Herstellerkürzel geprägt. Tabletten relativ groß im Durchmesser.","ampel":"gelb","einstufung":"Verschreibungspflichtig","gesetz":"AMG (verschreibungspflichtig)","begruendung":"Starkes Schmerz-/Fiebermittel, verschreibungspflichtig. Mit Rezept legal; ohne Rezept rechtlich problematisch.","bild":"","quellen":["amg","identa"]},{"id":"a-amoxicillin","kategorie":"arznei","name":"Antibiotika (z. B. Amoxicillin)","synonyme":["antibiotikum","amoxicillin","penicillin","azithromycin"],"wirkstoff":"Amoxicillin","praegung":"„AMOX 1000“/Code","farbe":"weiß/gelb","form":"kapsel/tablette","merkmale":"Oft große längliche Filmtablette (z. B. 1000 mg) mit Bruchrille oder Kapsel (gelb/rot). Prägung meist Wirkstoff + Dosis oder Herstellerkürzel.","ampel":"gelb","einstufung":"Verschreibungspflichtig","gesetz":"AMG (verschreibungspflichtig)","begruendung":"Antibiotika sind verschreibungspflichtig. Nur mit ärztlichem Rezept legal abzugeben.","bild":"","quellen":["amg","identa"]},{"id":"a-ramipril","kategorie":"arznei","name":"Blutdruckmittel (z. B. Ramipril)","synonyme":["ramipril","blutdrucksenker","ace hemmer","bisoprolol","amlodipin"],"wirkstoff":"Ramipril","praegung":"Dosis/Code","farbe":"weiß/rosa/gelb","form":"tablette","merkmale":"Kleine Tablette mit Bruchkerbe; Farbe je nach Dosis (z. B. 2,5/5/10 mg). Oft Dosiszahl und Herstellerkürzel geprägt.","ampel":"gelb","einstufung":"Verschreibungspflichtig","gesetz":"AMG (verschreibungspflichtig)","begruendung":"Herz-/Kreislaufmittel, verschreibungspflichtig. Mit Rezept legal.","bild":"","quellen":["amg","identa"]},{"id":"a-omeprazol","kategorie":"arznei","name":"Magenschutz (z. B. Omeprazol/Pantoprazol)","synonyme":["omeprazol","pantoprazol","protonenpumpenhemmer","ppi"],"wirkstoff":"Omeprazol","praegung":"„20“","farbe":"rosa/braun","form":"kapsel/tablette","merkmale":"Meist Hartkapsel mit Pellets (zweifarbig, z. B. rosa/braun) oder magensaftresistente Tablette. Prägung oft „20“ oder „40“. Pellets im Inneren sichtbar.","ampel":"gruen","einstufung":"Legal (kleine Dosen rezeptfrei)","gesetz":"AMG (niedrige Dosen apothekenpflichtig, höhere verschreibungspflichtig)","begruendung":"Magensäureblocker. Niedrige Dosierungen rezeptfrei in der Apotheke, höhere verschreibungspflichtig – beides legal.","bild":"","quellen":["amg","identa"]},{"id":"a-cetirizin","kategorie":"arznei","name":"Antiallergikum (z. B. Cetirizin/Loratadin)","synonyme":["cetirizin","loratadin","antihistaminikum","allergietablette"],"wirkstoff":"Cetirizin","praegung":"„C“/Code","farbe":"weiß","form":"rund","merkmale":"Kleine weiße Filmtablette, oft mit Bruchkerbe und Prägung („C10“ o. Ä.). Loratadin ähnlich. Durchmesser ca. 6–8 mm.","ampel":"gruen","einstufung":"Legal (rezeptfrei)","gesetz":"AMG (apothekenpflichtig/teils freiverkäuflich)","begruendung":"Allergiemittel, rezeptfrei erhältlich. Legal.","bild":"","quellen":["amg","identa"]},{"id":"a-l-thyroxin","kategorie":"arznei","name":"Schilddrüsenhormon (L-Thyroxin)","synonyme":["l-thyroxin","levothyroxin","euthyrox","l-thyrox"],"wirkstoff":"Levothyroxin","praegung":"Dosis (z. B. „100“)","farbe":"weiß/gelb","form":"rund","merkmale":"Sehr kleine, oft weiße Tablette mit tiefer Bruchkerbe (Kreuzkerbe). Dosis (25–200 µg) eingeprägt. Leicht zerbrechlich.","ampel":"gelb","einstufung":"Verschreibungspflichtig","gesetz":"AMG (verschreibungspflichtig)","begruendung":"Schilddrüsenhormon, verschreibungspflichtig. Mit Rezept legal.","bild":"","quellen":["amg","identa"]},{"id":"a-pille","kategorie":"arznei","name":"Antibabypille (orales Kontrazeptivum)","synonyme":["pille","antibabypille","verhütungspille","kontrazeptivum"],"wirkstoff":"Östrogen/Gestagen","praegung":"Wochentag/Code","farbe":"bunt","form":"rund (Blister)","merkmale":"Sehr kleine, oft bunte Dragees im Blister mit 21/28 Stück, häufig Wochentage aufgedruckt. Einzelne Tablette ca. 5–6 mm, glänzend überzogen.","ampel":"gelb","einstufung":"Verschreibungspflichtig","gesetz":"AMG (verschreibungspflichtig)","begruendung":"Hormonelle Verhütung, verschreibungspflichtig. Mit Rezept legal.","bild":"","quellen":["amg","identa"]},{"id":"a-sildenafil","kategorie":"arznei","name":"Sildenafil (Viagra)","synonyme":["viagra","sildenafil","potenzmittel"],"wirkstoff":"Sildenafil","praegung":"„VGR 50/100“ / „Pfizer“","farbe":"blau","form":"rautenförmig","merkmale":"Markant: blaue, rautenförmige (vierseitige) Filmtablette. Original-Viagra mit „Pfizer“ und „VGR 25/50/100“ geprägt. Generika meist weiß/rund. Auffällige blaue Farbe.","ampel":"gelb","einstufung":"Verschreibungspflichtig","gesetz":"AMG (verschreibungspflichtig)","begruendung":"Potenzmittel, verschreibungspflichtig. Mit Rezept legal; gefälschte „Online“-Ware ist gefährlich und illegal.","bild":"https://commons.wikimedia.org/wiki/Special:FilePath/Sildenafil%20citrate%20tablets.jpg","quellen":["amg","identa"]},{"id":"amg-1-1-dichlorethan","kategorie":"arznei","name":"1,1-Dichlorethan","synonyme":[],"wirkstoff":"1,1-Dichlorethan","praegung":"","farbe":"","form":"","ampel":"gelb","einstufung":"Verschreibungspflichtig (AMG)","kurz":"Verschreibungspflichtiger Arzneistoff – nur auf ärztliche Verschreibung erhältlich.","gesetz":"AMG § 48 (Verschreibungspflicht); Anlage zu § 1 Nr. 1 (AMVV)","rechtsgrundlage":"Arzneimittelverschreibungsverordnung (AMVV), Anlage zu § 1 Nr. 1","besonderheiten":"Auch Salze dieses Stoffes sind verschreibungspflichtig.","folgenBesitz":"Der bloße Besitz ist nicht strafbewehrt. Bei fehlender Berechtigung: gefahrenabwehrende Sicherstellung möglich.","folgenHandel":"§ 95 AMG: unerlaubtes Inverkehrbringen/Abgabe verschreibungspflichtiger Arzneimittel – Freiheitsstrafe bis 3 Jahre oder Geldstrafe; besonders schwere Fälle 1–10 Jahre; Versuch strafbar; fahrlässig bis 1 Jahr.","begruendung":"Verschreibungspflichtiger Wirkstoff nach der amtlichen AMG-Anlage. Abgabe nur in Apotheken gegen ärztliche Verschreibung.","bild":"","quellen":["amg","identa"]},{"id":"amg-1-2-dibromethan","kategorie":"arznei","name":"1,2-Dibromethan","sy